using CommunityToolkit.Diagnostics;

namespace Tarmi.Devices.Thermofisher.Instrument.ObjectModel.PathLiterals;

internal static class Instrument
{
    private static string ToStringImpl(string? fullTypeName)
    {
        Guard.IsNotNullOrWhiteSpace(fullTypeName);
        var idx = fullTypeName?.LastIndexOf('.' + nameof(Instrument), StringComparison.Ordinal);
        return
            idx.HasValue && idx.Value >= 0 ?
                fullTypeName![(idx.Value + 1)..].Replace('+', '.') :
                throw new InvalidOperationException();
    }

    public static string AsString => nameof(Instrument);

